text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "decision": "공개 출시 목표는 금요일 15:00 KST이며, smoke test가 통과해야 진행한다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 `smoke-theme-pack.mjs`를 재검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "`smoke-theme-pack.mjs`가 packageName 불일치를 무시하도록 변경",
        "result": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 출시는 내부 스트레치 목표로만 유지한다."
      }
    ],
    "non_decisions": [
      {
        "note": "README install steps는 목요일까지 검토하자는 언급이 있었지만 owner는 배정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로가 잘못되면 출시가 지연될 수 있다."
      },
      {
        "risk": "README install steps가 오래되면 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "직접 진술"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage note를 `action_items.md`에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "직접 진술"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "Minjun의 smoke 결과 게시 후(정확한 시각 미정)",
      "status": "조건부 예정",
      "source_certainty": "직접 진술(조건부)"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 전후로 Minjun의 smoke 결과를 확인한다.",
      "금요일 12:00 KST 전후로 Doyun의 실패 triage note 완료 여부를 확인한다.",
      "smoke 통과 후 tarball 경로를 확인한다.",
      "README install steps 검토의 owner 배정 여부를 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 넣을지 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너명, 예산, 보안 사고, 프로덕션 장애, 법무 승인 요구는 추가하지 않는다.",
      "최종 릴리스 승인권자, README 검토 owner, Hara의 정확한 마감 시각은 임의로 정하지 않는다.",
      "수요일 제안을 공식 출시 결정으로 바꾸지 않는다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 넣는다고 단정하지 않는다."
    ]
  },
  "non_invention_rules": [
    "fixture에 없는 고객명 또는 외부 파트너명, 예산, 보안 사고, 프로덕션 장애, 법무 승인 요구를 생성하지 않는다.",
    "명시되지 않은 owner, deadline, 승인권자는 임의로 채우지 않는다.",
    "내부 스트레치 목표를 공식 출시 결정으로 바꾸지 않는다.",
    "README 검토와 tarball 확인의 책임 범위를 fixture에 적힌 수준 이상으로 확장하지 않는다."
  ]
}
